var seed = GetInt(parameters, "seed", context.Seed);
var rows = GetInt(parameters, "rows", 8);
var cols = GetInt(parameters, "cols", 8);
var overlap = GetFloat(parameters, "overlap", 0.3f);
var roundness = GetFloat(parameters, "roundness", 0.6f);
var scaleColor = GetColor(parameters, "scaleColor", System.Windows.Media.Color.FromRgb(60, 140, 80));
var gapColor = GetColor(parameters, "gapColor", System.Windows.Media.Color.FromRgb(30, 60, 40));
var highlight = GetFloat(parameters, "highlight", 0.4f);
var shadow = GetFloat(parameters, "shadow", 0.3f);
var colorVar = GetFloat(parameters, "colorVariation", 0.2f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var sR = scaleColor.R / 255f; var sG = scaleColor.G / 255f; var sB = scaleColor.B / 255f;
var gR = gapColor.R / 255f; var gG = gapColor.G / 255f; var gB = gapColor.B / 255f;

var scaleW = 1f / cols;
var scaleH = 1f / rows;

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Determine which scale we're in (offset rows)
    var row = (int)(v / scaleH);
    var col = (int)(u / scaleW);
    var rowOffset = (row % 2) * 0.5f;

    // Local coordinates within scale
    var localU = (u - col * scaleW) / scaleW;
    var localV = (v - row * scaleH) / scaleH;

    // Check neighboring scales for overlap
    var bestScaleU = localU;
    var bestScaleV = localV;
    var bestDist = 1f;

    for (var dr = -1; dr <= 1; dr++)
    {
        for (var dc = -1; dc <= 1; dc++)
        {
            var nr = row + dr;
            var nc = col + dc;
            var noff = (nr % 2) * 0.5f;
            var cx = (nc + noff) * scaleW;
            var cy = nr * scaleH;

            var dx = (u - cx) / scaleW;
            var dy = (v - cy) / scaleH;

            // Elliptical distance
            var dist = dx * dx + dy * dy / (roundness * roundness);
            if (dist < bestDist)
            {
                bestDist = dist;
                bestScaleU = dx + 0.5f;
                bestScaleV = dy / roundness + 0.5f;
            }
        }
    }

    // Per-scale hash
    var nearRow = (int)((v - (bestScaleV - 0.5f) * scaleH * roundness) / scaleH);
    var nearCol = (int)((u - (bestScaleU - 0.5f) * scaleW) / scaleW);
    var nearNoff = (nearRow % 2) * 0.5f;
    if (u < (nearCol + nearNoff) * scaleW) nearCol--;
    var hash = HashToUnit(nearCol * 31 + nearRow * 17, seed, 999);

    // Distance to scale edge
    var edgeDist = MathF.Sqrt(bestDist);

    float r, g, b;
    if (edgeDist > 1f - overlap * 0.8f)
    {
        // Gap between scales
        r = gR; g = gG; b = gB;
    }
    else
    {
        // Inside scale
        var varAmt = (hash - 0.5f) * colorVar;
        r = Math.Clamp(sR + varAmt, 0f, 1f);
        g = Math.Clamp(sG + varAmt * 0.8f, 0f, 1f);
        b = Math.Clamp(sB + varAmt * 0.6f, 0f, 1f);

        // Highlight (top-left of scale)
        var hl = (1f - bestScaleU) * 0.5f + (1f - bestScaleV) * 0.5f;
        hl = MathF.Max(0f, hl - 0.3f) * highlight;

        // Shadow (bottom-right of scale)
        var sh = (bestScaleU * 0.5f + bestScaleV * 0.5f - 0.3f) * shadow;
        sh = MathF.Max(0f, sh);

        r = Math.Clamp(r + hl - sh, 0f, 1f);
        g = Math.Clamp(g + hl * 0.8f - sh * 0.8f, 0f, 1f);
        b = Math.Clamp(b + hl * 0.6f - sh * 0.6f, 0f, 1f);
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, r, g, b, 1f);
});

return buffer;
}
